#!/usr/bin/env dotnet
using System;

// Test stackalloc with nint (native-sized integer)
Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  [{i}] = {nints[i]}");

// Test stackalloc with nuint (unsigned native-sized integer)
Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 100;
nuints[1] = 200;
nuints[2] = 300;

Console.WriteLine("\nSpan<nuint> via stackalloc:");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  [{i}] = {nuints[i]}");

Console.WriteLine($"\nnint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

